import{_ as a,c as s,o as n,a5 as i}from"./chunks/framework.CgT1UzWm.js";const u=JSON.parse('{"title":"Changelog v3.8.0 (2025-02-11)","description":"NpgsqlRest v3.8.0: Release notes: New Feature: Configuration Key Validation; Removed; Kestrel Configuration Validation; Syntax Highlighted --config Output","frontmatter":{"description":"NpgsqlRest v3.8.0: Release notes: New Feature: Configuration Key Validation; Removed; Kestrel Configuration Validation; Syntax Highlighted --config Output","head":[["link",{"rel":"canonical","href":"https://npgsqlrest.github.io/guide/changelog/v3.8.0.html"}],["meta",{"property":"og:url","content":"https://npgsqlrest.github.io/guide/changelog/v3.8.0.html"}],["meta",{"property":"og:type","content":"article"}],["meta",{"property":"og:title","content":"Changelog v3.8.0 (2025-02-11)"}],["meta",{"property":"og:description","content":"NpgsqlRest v3.8.0: Release notes: New Feature: Configuration Key Validation; Removed; Kestrel Configuration Validation; Syntax Highlighted --config Output"}],["meta",{"property":"og:image","content":"https://npgsqlrest.github.io/og-image.png"}],["meta",{"name":"twitter:card","content":"summary_large_image"}],["meta",{"name":"twitter:title","content":"Changelog v3.8.0 (2025-02-11)"}],["meta",{"name":"twitter:description","content":"NpgsqlRest v3.8.0: Release notes: New Feature: Configuration Key Validation; Removed; Kestrel Configuration Validation; Syntax Highlighted --config Output"}],["meta",{"name":"twitter:image","content":"https://npgsqlrest.github.io/og-image.png"}]]},"headers":[],"relativePath":"guide/changelog/v3.8.0.md","filePath":"guide/changelog/v3.8.0.md","lastUpdated":1782480183000}'),t={name:"guide/changelog/v3.8.0.md"};function o(l,e,r,d,p,c){return n(),s("div",null,e[0]||(e[0]=[i('<h1 id="changelog-v3-8-0-2025-02-11" tabindex="-1">Changelog v3.8.0 (2025-02-11) <a class="header-anchor" href="#changelog-v3-8-0-2025-02-11" aria-label="Permalink to &quot;Changelog v3.8.0 (2025-02-11)&quot;">​</a></h1><h2 id="version-3-8-0-2025-02-11" tabindex="-1">Version <a href="https://github.com/NpgsqlRest/NpgsqlRest/tree/3.8.0" target="_blank" rel="noreferrer">3.8.0</a> (2025-02-11) <a class="header-anchor" href="#version-3-8-0-2025-02-11" aria-label="Permalink to &quot;Version [3.8.0](https://github.com/NpgsqlRest/NpgsqlRest/tree/3.8.0) (2025-02-11)&quot;">​</a></h2><p><a href="https://github.com/NpgsqlRest/NpgsqlRest/compare/3.7.0...3.8.0" target="_blank" rel="noreferrer">Full Changelog</a></p><h3 id="new-feature-configuration-key-validation" tabindex="-1">New Feature: Configuration Key Validation <a class="header-anchor" href="#new-feature-configuration-key-validation" aria-label="Permalink to &quot;New Feature: Configuration Key Validation&quot;">​</a></h3><p>Added startup validation that checks all configuration keys in <code>appsettings.json</code> against the known defaults schema. This catches typos and unknown keys that would otherwise be silently ignored (e.g., <code>LogCommand</code> instead of <code>LogCommands</code>).</p><p>Controlled by the new <code>Config:ValidateConfigKeys</code> setting with three modes:</p><ul><li><code>&quot;Warning&quot;</code> (default) — logs warnings for unknown keys, startup continues.</li><li><code>&quot;Error&quot;</code> — logs errors for unknown keys and exits the application.</li><li><code>&quot;Ignore&quot;</code> — no validation.</li></ul><details class="code-collapsible" open><summary>json</summary><div class="language-json vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes catppuccin-latte catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#40A02B;--shiki-dark:#A6E3A1;">&quot;Config&quot;</span><span style="--shiki-light:#4C4F69;--shiki-dark:#CDD6F4;">: </span><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">{</span></span>\n<span class="line"><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">  &quot;</span><span style="--shiki-light:#1E66F5;--shiki-dark:#89B4FA;">ValidateConfigKeys</span><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">&quot;</span><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">:</span><span style="--shiki-light:#40A02B;--shiki-dark:#A6E3A1;"> &quot;Warning&quot;</span></span>\n<span class="line"><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">}</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div></details><p>Example output:</p><details class="code-collapsible" open><summary>code</summary><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes catppuccin-latte catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>[12:34:56 WRN] Unknown configuration key: NpgsqlRest:KebabCaselUrls</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div></details><h3 id="removed" tabindex="-1">Removed <a class="header-anchor" href="#removed" aria-label="Permalink to &quot;Removed&quot;">​</a></h3><ul><li>Removed the <code>Config:ExposeAsEndpoint</code> option. Use the <code>--config</code> CLI switch to inspect configuration instead.</li></ul><h3 id="kestrel-configuration-validation" tabindex="-1">Kestrel Configuration Validation <a class="header-anchor" href="#kestrel-configuration-validation" aria-label="Permalink to &quot;Kestrel Configuration Validation&quot;">​</a></h3><p>Configuration key validation also covers the <code>Kestrel</code> section, checking against the known Kestrel schema including <code>Limits</code>, <code>Http2</code>, <code>Http3</code>, and top-level flags like <code>DisableStringReuse</code> and <code>AllowSynchronousIO</code>. User-defined endpoint and certificate names under <code>Endpoints</code> and <code>Certificates</code> remain open-ended and won&#39;t trigger warnings.</p><h3 id="syntax-highlighted-config-output" tabindex="-1">Syntax Highlighted <code>--config</code> Output <a class="header-anchor" href="#syntax-highlighted-config-output" aria-label="Permalink to &quot;Syntax Highlighted `--config` Output&quot;">​</a></h3><p>The <code>--config</code> CLI switch now outputs JSON with syntax highlighting (keys, strings, numbers/booleans, and structural characters in distinct colors). When output is redirected to a file, plain JSON is emitted without color codes. The <code>--config</code> switch can now appear anywhere in the argument list and be combined with config files and <code>--key=value</code> overrides.</p><h3 id="improved-cli-error-handling" tabindex="-1">Improved CLI Error Handling <a class="header-anchor" href="#improved-cli-error-handling" aria-label="Permalink to &quot;Improved CLI Error Handling&quot;">​</a></h3><p>Unknown command-line parameters now display a clear error message with a <code>--help</code> hint instead of an unhandled exception stack trace.</p><h3 id="universal-fallback-handler-for-all-upload-handlers" tabindex="-1">Universal <code>fallback_handler</code> for All Upload Handlers <a class="header-anchor" href="#universal-fallback-handler-for-all-upload-handlers" aria-label="Permalink to &quot;Universal `fallback_handler` for All Upload Handlers&quot;">​</a></h3><p>The <code>fallback_handler</code> parameter, previously Excel-only, is now available on all upload handlers via <code>BaseUploadHandler</code>. When a handler&#39;s format validation fails and a <code>fallback_handler</code> is configured, processing is automatically delegated to the named fallback handler.</p><p>This enables scenarios like: CSV format check fails on a binary file → fall back to <code>large_object</code> or <code>file_system</code> to save the raw file for analysis.</p><details class="code-collapsible" open><summary>sql</summary><div class="language-sql vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki shiki-themes catppuccin-latte catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#8839EF;--shiki-dark:#CBA6F7;">comment on function my_csv_upload(json) is </span><span style="--shiki-light:#40A02B;--shiki-dark:#A6E3A1;">&#39;</span></span>\n<span class="line"><span style="--shiki-light:#40A02B;--shiki-dark:#A6E3A1;">@upload for csv</span></span>\n<span class="line"><span style="--shiki-light:#40A02B;--shiki-dark:#A6E3A1;">@check_format = true</span></span>\n<span class="line"><span style="--shiki-light:#40A02B;--shiki-dark:#A6E3A1;">@fallback_handler = large_object</span></span>\n<span class="line"><span style="--shiki-light:#40A02B;--shiki-dark:#A6E3A1;">@row_command = select process_row($1,$2)</span></span>\n<span class="line"><span style="--shiki-light:#40A02B;--shiki-dark:#A6E3A1;">&#39;</span><span style="--shiki-light:#4C4F69;--shiki-dark:#CDD6F4;">;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div></details><h3 id="optional-path-parameters" tabindex="-1">Optional Path Parameters <a class="header-anchor" href="#optional-path-parameters" aria-label="Permalink to &quot;Optional Path Parameters&quot;">​</a></h3><p>Path parameters now support the ASP.NET Core optional parameter syntax <code>{param?}</code>. When a path parameter is marked as optional and the corresponding PostgreSQL function parameter has a default value, omitting the URL segment will use the PostgreSQL default:</p><details class="code-collapsible" open><summary>sql</summary><div class="language-sql vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki shiki-themes catppuccin-latte catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#8839EF;--shiki-dark:#CBA6F7;">create</span><span style="--shiki-light:#8839EF;--shiki-dark:#CBA6F7;"> function</span><span style="--shiki-light:#1E66F5;--shiki-light-font-style:italic;--shiki-dark:#89B4FA;--shiki-dark-font-style:italic;"> get_item</span><span style="--shiki-light:#4C4F69;--shiki-dark:#CDD6F4;">(p_id </span><span style="--shiki-light:#8839EF;--shiki-dark:#CBA6F7;">int</span><span style="--shiki-light:#8839EF;--shiki-dark:#CBA6F7;"> default</span><span style="--shiki-light:#FE640B;--shiki-dark:#FAB387;"> 42</span><span style="--shiki-light:#4C4F69;--shiki-dark:#CDD6F4;">) </span><span style="--shiki-light:#8839EF;--shiki-dark:#CBA6F7;">returns</span><span style="--shiki-light:#8839EF;--shiki-dark:#CBA6F7;"> text</span><span style="--shiki-light:#4C4F69;--shiki-dark:#CDD6F4;"> ...</span></span>\n<span class="line"><span style="--shiki-light:#8839EF;--shiki-dark:#CBA6F7;">comment on function get_item(int) is </span><span style="--shiki-light:#40A02B;--shiki-dark:#A6E3A1;">&#39;</span></span>\n<span class="line"><span style="--shiki-light:#40A02B;--shiki-dark:#A6E3A1;">HTTP GET /items/{p_id?}</span></span>\n<span class="line"><span style="--shiki-light:#40A02B;--shiki-dark:#A6E3A1;">&#39;</span><span style="--shiki-light:#4C4F69;--shiki-dark:#CDD6F4;">;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div></details><ul><li><code>GET /items/5</code> → uses the provided value <code>5</code></li><li><code>GET /items/</code> → uses the PostgreSQL default <code>42</code></li></ul><p>This also works with <code>query_string_null_handling null_literal</code> to pass NULL via the literal string <code>&quot;null&quot;</code> in the path for any parameter type:</p><details class="code-collapsible" open><summary>sql</summary><div class="language-sql vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki shiki-themes catppuccin-latte catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#8839EF;--shiki-dark:#CBA6F7;">create</span><span style="--shiki-light:#8839EF;--shiki-dark:#CBA6F7;"> function</span><span style="--shiki-light:#1E66F5;--shiki-light-font-style:italic;--shiki-dark:#89B4FA;--shiki-dark-font-style:italic;"> get_item</span><span style="--shiki-light:#4C4F69;--shiki-dark:#CDD6F4;">(p_id </span><span style="--shiki-light:#8839EF;--shiki-dark:#CBA6F7;">int</span><span style="--shiki-light:#8839EF;--shiki-dark:#CBA6F7;"> default</span><span style="--shiki-light:#8839EF;--shiki-dark:#CBA6F7;"> null</span><span style="--shiki-light:#4C4F69;--shiki-dark:#CDD6F4;">) </span><span style="--shiki-light:#8839EF;--shiki-dark:#CBA6F7;">returns</span><span style="--shiki-light:#8839EF;--shiki-dark:#CBA6F7;"> text</span><span style="--shiki-light:#4C4F69;--shiki-dark:#CDD6F4;"> ...</span></span>\n<span class="line"><span style="--shiki-light:#8839EF;--shiki-dark:#CBA6F7;">comment on function get_item(int) is </span><span style="--shiki-light:#40A02B;--shiki-dark:#A6E3A1;">&#39;</span></span>\n<span class="line"><span style="--shiki-light:#40A02B;--shiki-dark:#A6E3A1;">HTTP GET /items/{p_id}</span></span>\n<span class="line"><span style="--shiki-light:#40A02B;--shiki-dark:#A6E3A1;">query_string_null_handling null_literal</span></span>\n<span class="line"><span style="--shiki-light:#40A02B;--shiki-dark:#A6E3A1;">&#39;</span><span style="--shiki-light:#4C4F69;--shiki-dark:#CDD6F4;">;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div></details><ul><li><code>GET /items/null</code> → passes SQL NULL to the function</li></ul><h3 id="fixes" tabindex="-1">Fixes <a class="header-anchor" href="#fixes" aria-label="Permalink to &quot;Fixes&quot;">​</a></h3><ul><li>Fixed query string overload resolution not accounting for path parameters. GET endpoints with path parameters and overloaded functions (same name, different signatures) would resolve to the wrong function. The body JSON overload resolution already handled this correctly.</li><li>Added missing <code>QueryStringNullHandling</code> and <code>TextResponseNullHandling</code> entries to <code>ConfigDefaults</code>, which caused them to be absent from <code>--config</code> output.</li><li>Added missing <code>Pattern</code>, <code>MinLength</code>, and <code>MaxLength</code> properties to default validation rule schemas in <code>ConfigDefaults</code>.</li></ul><h3 id="machine-readable-cli-commands-for-tool-integration" tabindex="-1">Machine-Readable CLI Commands for Tool Integration <a class="header-anchor" href="#machine-readable-cli-commands-for-tool-integration" aria-label="Permalink to &quot;Machine-Readable CLI Commands for Tool Integration&quot;">​</a></h3><p>Added new CLI commands designed for programmatic consumption by tools like pgdev. All JSON-outputting commands use syntax highlighting when run in a terminal and emit plain JSON when piped or redirected.</p><h4 id="version-json" tabindex="-1"><code>--version --json</code> <a class="header-anchor" href="#version-json" aria-label="Permalink to &quot;`--version --json`&quot;">​</a></h4><p>Outputs version information as structured JSON including all assembly versions, runtime, platform RID, and directories:</p><details class="code-collapsible" open><summary>code</summary><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes catppuccin-latte catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>npgsqlrest --version --json</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div></details><h4 id="validate-json" tabindex="-1"><code>--validate [--json]</code> <a class="header-anchor" href="#validate-json" aria-label="Permalink to &quot;`--validate [--json]`&quot;">​</a></h4><p>Pre-flight check that validates configuration keys against known defaults and tests the database connection, then exits with code 0 (success) or 1 (failure):</p><details class="code-collapsible" open><summary>code</summary><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes catppuccin-latte catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>npgsqlrest --validate</span></span>\n<span class="line"><span>npgsqlrest --validate --json</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div></details><h4 id="config-schema" tabindex="-1"><code>--config-schema</code> <a class="header-anchor" href="#config-schema" aria-label="Permalink to &quot;`--config-schema`&quot;">​</a></h4><p>Outputs a <a href="https://json-schema.org" target="_blank" rel="noreferrer">JSON Schema (draft-07)</a> describing the full <code>appsettings.json</code> configuration structure — types, defaults, and enum constraints. Can be used for IDE autocomplete via the <code>$schema</code> property or as the foundation for config editing UIs:</p><details class="code-collapsible" open><summary>code</summary><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes catppuccin-latte catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>npgsqlrest --config-schema</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div></details><h4 id="annotations" tabindex="-1"><code>--annotations</code> <a class="header-anchor" href="#annotations" aria-label="Permalink to &quot;`--annotations`&quot;">​</a></h4><p>Outputs all 44 supported SQL comment annotations as a JSON array with name, aliases, syntax, and description for each:</p><details class="code-collapsible" open><summary>code</summary><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes catppuccin-latte catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>npgsqlrest --annotations</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div></details><h4 id="endpoints" tabindex="-1"><code>--endpoints</code> <a class="header-anchor" href="#endpoints" aria-label="Permalink to &quot;`--endpoints`&quot;">​</a></h4><p>Connects to the database, discovers all generated REST endpoints, outputs full metadata (method, path, routine info, parameters, return columns, authorization, custom parameters), then exits. Logging is suppressed to keep output clean:</p><details class="code-collapsible" open><summary>code</summary><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes catppuccin-latte catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>npgsqlrest --endpoints</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div></details><h4 id="config-updated" tabindex="-1"><code>--config</code> (updated) <a class="header-anchor" href="#config-updated" aria-label="Permalink to &quot;`--config` (updated)&quot;">​</a></h4><p>The <code>--config --json</code> flag has been removed. The <code>--config</code> command now always uses automatic detection: syntax highlighted in terminal, plain JSON when output is piped or redirected.</p><h3 id="stats-endpoints-format-query-string-override" tabindex="-1">Stats Endpoints: <code>format</code> Query String Override <a class="header-anchor" href="#stats-endpoints-format-query-string-override" aria-label="Permalink to &quot;Stats Endpoints: `format` Query String Override&quot;">​</a></h3><p>Stats endpoints now accept an optional <code>format</code> query string parameter that overrides the configured <code>Stats:OutputFormat</code> setting per-request. Valid values are <code>html</code> and <code>json</code>.</p><details class="code-collapsible" open><summary>code</summary><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes catppuccin-latte catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>GET /api/stats/routines?format=json</span></span>\n<span class="line"><span>GET /api/stats/tables?format=html</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div></details><hr>',54)]))}const g=a(t,[["render",o]]);export{u as __pageData,g as default};
